# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
import re

app = Flask(__name__)

# template for welcome page
welcome_template = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Welcome</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            background-color: #f2f2f2;
        }
        
        .container {
            width: 80%;
            margin: 40px auto;
            text-align: center;
        }
        
        h1 {
            color: #007bff;
        }
        
        p {
            font-size: 18px;
            padding-bottom: 20px;
            border-bottom: 1px solid #ddd;
        }
        
        .italic {
            font-style: italic;
        }
        
        .bold {
            font-weight: bold;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Welcome, {{ username }}!</h1>
        <p>{{ bio | replace('{\\*}', '*') | replace('{/_}', '_') }}</p>
        <p>Location: {{ location }}</p>
        <p>Status: {{ status | replace('{\\*}', '*') | replace('{/_}', '_') }}</p>
    </div>
</body>
</html>
"""

@app.route('/welcome', methods=['GET'])
def welcome():
    username = request.args.get('username')
    bio = request.args.get('bio')
    location = request.args.get('location')
    status = request.args.get('status')

    # basic formatting
    bio = re.sub('{\\*(.*?)\\*}', r'<b>\1</b>', bio)
    bio = re.sub('{/(.*?)/}', r'<i>\1</i>', bio)
    status = re.sub('{\\*(.*?)\\*}', r'<b>\1</b>', status)
    status = re.sub('{/(.*?)/}', r'<i>\1</i>', status)

    return render_template_string(welcome_template, username=username, bio=bio, location=location, status=status)

if __name__ == '__main__':
    app.run(debug=True)